import React from "react"
import { properties } from '../../properties/properties.js'
import footer from './footer.png'

function dynamicSort(property) {
    var sortOrder = 1;
    if(property[0] === "-") {
        sortOrder = -1;
        property = property.substr(1);
    }
    return function (a,b) {
        /* next line works with strings and numbers, 
         * and you may want to customize it to your needs
         */
        var result = (a[property] < b[property]) ? -1 : (a[property] > b[property]) ? 1 : 0;
        return result * sortOrder;
    }
  }

  function dynamicDescSort(property) {
    var sortOrder = 1;
    if(property[0] === "-") {
        sortOrder = -1;
        property = property.substr(1);
    }
    return function (a,b) {
        /* next line works with strings and numbers, 
         * and you may want to customize it to your needs
         */
        var result = (a[property] > b[property]) ? -1 : (a[property] < b[property]) ? 1 : 0;
        return result * sortOrder;
    }
  }

var globalSignoutTeamTime = [];

class CyberRaptorV2 extends React.Component {

    constructor(props) {
        super(props);
        this.state = { screen: 0, result: [], assignResult: []
        };
    }


    toggle24hr(time, onoff){
        if(onoff==undefined) onoff = isNaN(time.replace(':',''))//auto-detect format
        var pm = time.toString().toLowerCase().indexOf('pm')>-1 //check if 'pm' exists in the time string
        time = time.toString().toLowerCase().replace(/[ap]m/,'').split(':') //convert time to an array of numbers
        time[0] = Number(time[0])
        if(onoff){//convert to 24 hour:
            if((pm && time[0]!=12)) time[0] += 12
            else if(!pm && time[0]==12) time[0] = '00'  //handle midnight
            if(String(time[0]).length==1) time[0] = '0'+time[0] //add leading zeros if needed
        }else{ //convert to 12 hour:
            pm = time[0]>=12
            if(!time[0]) time[0]=12 //handle midnight
            else if(pm && time[0]!=12) time[0] -= 12
        }
        return onoff ? time.join(':').trim() : time.join(':')+(pm ? 'pm' : 'am')
    }


    findTeamTimeFunc = (timeStart, teamSignoutTimeArray, duration) => {
        //console.log(teamSignoutTimeArray)
        //console.log(timeStart)
        //console.log(duration)
        //startTime, endTime
        teamSignoutTimeArray.sort(this.sortTeamTimeAsc)
        var endLoop=false

        if (teamSignoutTimeArray.length < 1) {
          return timeStart
        }

        if (teamSignoutTimeArray.length === 1) {
          var dTimeStart = new Date('1970-01-01T' + this.toggle24hr(timeStart) + ":00")
          dTimeStart.setMinutes(dTimeStart.getMinutes() + duration)
          var dStartTime = new Date('1970-01-01T' + this.toggle24hr(teamSignoutTimeArray[0].startTime) + ":00")
          if (dTimeStart <= dStartTime) 
            return timeStart
          else
            return teamSignoutTimeArray[0].endTime
        }

        for (var x=0;x<teamSignoutTimeArray.length&&!endLoop;x++) {
          //console.log(timeStart)
          var dTimeStart = new Date('1970-01-01T' + this.toggle24hr(timeStart) + ":00")
          dTimeStart.setMinutes(dTimeStart.getMinutes() + duration)
          var dStartTime = new Date('1970-01-01T' + this.toggle24hr(teamSignoutTimeArray[x].startTime) + ":00")
          if (dTimeStart <= dStartTime) 
            return timeStart
          else
            timeStart = teamSignoutTimeArray[x].endTime
        }
      //console.log(timeStart)
        return timeStart

    }

    fixOrder = (assigned_ho) => {

        for (var index in assigned_ho) {
            assigned_ho[index].index = index
        }
        return assigned_ho
    }


    runConfirm = () => {
        this.setState({screen: 2})
      }


      runMove = (evt) => {
        //console.log(document.getElementById("move_" + evt.currentTarget.value).value)
        //console.log(evt.currentTarget.value)

        var teams = this.state.result.team
        var findHO

        for(var index in teams) {
            var team = teams[index]
            for (var index2 in team.assigned_ho) {
                if (team.assigned_ho[index2].MRN === evt.currentTarget.value) {
                    findHO = team.assigned_ho[index2]
                    findHO.step = "MANUAL"
                    team.assigned_ho.splice(index2, 1)
                    team.current_ho -= 1
                    this.fixOrder(team.assigned_ho)
                }
            }
        }

        for(var index in teams) {
            var team = teams[index]
            if (team.name === document.getElementById("move_" + evt.currentTarget.value).value) {
                team.assigned_ho.push(findHO)
                team.current_ho += 1
                this.fixOrder(team.assigned_ho)
            }
        }




        var result = this.state.result
        result.team = teams

        console.log(result)

        this.setState({result: result})
      }


    runMoveToAssign = (evt) => {

        var HOTeams = this.state.result.HOTeams
        var teams = this.state.result.team

        for (var index in HOTeams) {
            if (HOTeams[index].MRN === evt.currentTarget.value) {
                for (var index2 in teams){
                    if (teams[index2].name === document.getElementById("move_" + evt.currentTarget.value).value) {
                        var ho = HOTeams[index]
                        //ho.index = teams[index2].current_ho
                        ho.step = "MANUAL"
                        teams[index2].assigned_ho.push(ho)
                        teams[index2].current_ho += 1
                        this.fixOrder(teams[index2].assigned_ho)
                    }
                }
                HOTeams.splice(index,1)
            }
        }

        var result = this.state.result
        result.HOTeams = HOTeams
        result.team = teams

        console.log(result)

        this.setState({result: result})

    }


    runMoveToAssignRaw = (evt) => {

        var patientTeams = this.state.assignResult.patientList
        var teams = this.state.assignResult.team

        for (var index in patientTeams) {
            var eachPatients = patientTeams[index]
            for (var index2 in eachPatients) {
                if (eachPatients[index2].MRN === evt.currentTarget.value) {
                    for (var index2 in teams){
                        if (teams[index2].name === document.getElementById("moveFrom_" + evt.currentTarget.value).value) {
                            var ho = HOTeams[index]
                            //ho.index = teams[index2].current_ho
                            ho.step = "MANUAL"
                            teams[index2].assigned_ho.push(ho)
                            teams[index2].current_ho += 1
                            this.fixOrder(teams[index2].assigned_ho)
                        }
                    }
                    eachPatients.splice(index2,1)
                }
            }
        }

        var result = this.state.assignResult
        result.patientList = patientTeams
        result.team = teams

        console.log(result)

        this.setState({assignResult: result})

    }



    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/getrawdata`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({assignResult: response})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }


    render() {


        var header = "Loading ..."
        var content = []


        if (this.state.screen == 1 ) {
            var teamContent = []


            header = ""
            teamContent.push(<div style={{fontSize: "16px", color: "green"}}><br></br><u><b>Pre-assign the following patients before running algorithm</b></u><br></br>*** NOTE - in some cases the lists may have doubled patients, so the total number may be smaller than the sum of the lists. ***<br></br><br></br></div>)


            var team2 = []
            var remainPatients = this.state.assignResult.patientList
            this.state.assignResult.team.map(Record => team2.push(<option key={Record.name} value={Record.name}>{Record.name}</option>))


            for (var key in remainPatients) {

                if (remainPatients[key].patients.length > 0)
                    teamContent.push(<div style={{fontSize: "16px", marginBottom: "20px", marginTop: "10px"}}><u>{remainPatients[key].name}</u></div>)

                for (var key2 in remainPatients[key].patients) {
                    var singlePatient = remainPatients[key].patients[key2]
                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (singlePatient.COVID.length > 0) {
                    covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {singlePatient.COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + remainPatients[key].name
                    if (remainPatients[key].name === "Medicine X Robin") {
                    teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }
                    var remainLocation = ""
                    try {
                    if (singlePatient.Location.length > 0) {
                        remainLocation = " (" + singlePatient.Location + ")"
                    } 
                    } catch (e) {}
                    teamContent.push(<div style={{fontSize: "14px"}}><font style={{color: "#8B4513"}}><b>MRN: {singlePatient.MRN} {singlePatient.Name} {singlePatient.Age} {singlePatient.Sex} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font>{covidString}<br></br><font style={{color: 'blue'}}>{singlePatient.OneLiner ? singlePatient.OneLiner : ""}</font><div>assign to <select id={"moveFrom_" + singlePatient.MRN}>{team2}</select> <button style={{marginLeft: '12px'}} onClick={this.runMoveToAssign} value={singlePatient.MRN}>go</button></div><br></br></div>)
                }
            }


            content.push(teamContent)
            content.push(<hr></hr>)


            var team = this.state.assignResult.team

            for (var key3 in team) {


                var color = "black"
                if (team[key3].assigned_ho.length == 3) {
                    color = "red"
                }

                var duty = team[key3].duty 
                if (duty.length > 0) {
                    duty = ", " + duty
                }

                content.push(<div style={{marginTop: "40px", color: color}}><u>{team[key3].name} ({team[key3].census} pts{duty})</u></div>)


                var assigned_ho = team[key3].assigned_ho
                for (var key4 in assigned_ho) {
                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (assigned_ho[key4].COVID.length > 0) {
                        covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {assigned_ho[key4].COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + assigned_ho[key4].team
                    if (assigned_ho[key4].team === "Medicine X Robin") {
                        teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }
                    var remainLocation = ""
                    try {
                    if (assigned_ho[key4].Location.length > 0) {
                        remainLocation = " (" + assigned_ho[key4].Location + ")"
                    } 
                    } catch (e) {}
                    content.push(<div style={{fontSize: "14px", marginTop: "15px"}}><font style={{color: "#8B4513"}}><b>MRN: {assigned_ho[key4].MRN} {assigned_ho[key4].Name} {assigned_ho[key4].Age} {assigned_ho[key4].Sex} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font> - {assigned_ho[key4].step}<div>{covidString}</div><div style={{marginTop: "10px"}}><font style={{color: 'blue'}}>{assigned_ho[key4].OneLiner ? assigned_ho[key4].OneLiner : ""}</font></div><div style={{marginTop: "10px"}}>move to <select id={"move_" + assigned_ho[key4].MRN}>{team2}</select> <button style={{marginLeft: '12px'}} onClick={this.runMove} value={assigned_ho[key4].MRN}>submit</button></div><br></br></div>)
                }

            }

           content.push(<div style={{marginBottom: "50px"}}>&nbsp;</div>)


           content.push(<button style={{height: "30px", width: "150px", fontSize: "16px"}} onClick={this.runConfirm}>Run Algorithm</button>)
           content.push(<div style={{marginBottom: "50px"}}>&nbsp;</div>)

        }



        if (this.state.screen == 1 && this.state.result.totalHO == 0) {

            header = ""
            content.push(<div style={{fontSize: "16px", color: "green", marginTop: "20px"}}>Don't have any patient to admit yet!</div>)
        }


        if (this.state.screen == 1 && this.state.result.totalHO > 0) {


            header = ""

            var HOTeams = this.state.result.HOTeams

            var team2 = []

            //var team =  this.state.result.team.sort(dynamicSort("name"));
            var team = this.state.result.team
            team.map(Record => team2.push(<option key={Record.name} value={Record.name}>{Record.name}</option>))

            if (HOTeams.length > 0) {

                content.push(<div style={{fontSize: "16px", color: "green", marginTop: "50px"}}>
                    <div><u><b>Please assign the following patients</b></u></div>
                    <div style={{marginTop: "15px"}}>*** NOTE - in some cases the lists may have doubled patients, so the total number may be smaller than the sum of the lists. ***</div>
                </div>)


                for (var key in HOTeams) {
                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (HOTeams[key].COVID.length > 0) {
                        covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {HOTeams[key].COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + HOTeams[key].team
                    if (HOTeams[key].team === "Medicine X Robin") {
                        teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }
                    var remainLocation = ""
                    try {
                        if (HOTeams[key].Location.length > 0) {
                            remainLocation = " (" + HOTeams[key].Location + ")"
                        } 
                    } catch (e) {}
                    content.push(<div style={{fontSize: "14px", marginTop: "25px"}}><font style={{color: "#8B4513"}}><b>MRN: {HOTeams[key].MRN} {HOTeams[key].Name} {HOTeams[key].Age} {HOTeams[key].Sex} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font><div>{covidString}</div><div style={{marginTop: "10px"}}><font style={{color: 'blue'}}>{HOTeams[key].OneLiner ? HOTeams[key].OneLiner : ""}</font></div><div style={{marginTop: "10px"}}>move to <select id={"move_" + HOTeams[key].MRN}>{team2}</select> <button style={{marginLeft: '12px'}} onClick={this.runMoveToAssign} value={HOTeams[key].MRN}>submit</button></div><br></br></div>)
                }

            }


            content.push(<hr></hr>)


            for (var key2 in team) {


                var color = "black"
                if (team[key2].assigned_ho.length == 3) {
                    color = "red"
                }

                var duty = team[key2].duty 
                if (duty.length > 0) {
                    duty = ", " + duty
                }

                content.push(<div style={{marginTop: "40px", color: color}}><u>{team[key2].name} ({team[key2].census} pts{duty})</u></div>)


                var assigned_ho = team[key2].assigned_ho
                for (var key3 in assigned_ho) {
                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (assigned_ho[key3].COVID.length > 0) {
                        covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {assigned_ho[key3].COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + assigned_ho[key3].team
                    if (assigned_ho[key3].team === "Medicine X Robin") {
                        teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }
                    var remainLocation = ""
                    try {
                    if (assigned_ho[key3].Location.length > 0) {
                        remainLocation = " (" + assigned_ho[key3].Location + ")"
                    } 
                    } catch (e) {}
                    content.push(<div style={{fontSize: "14px", marginTop: "15px"}}><font style={{color: "#8B4513"}}><b>MRN: {assigned_ho[key3].MRN} {assigned_ho[key3].Name} {assigned_ho[key3].Age} {assigned_ho[key3].Sex} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font> - {assigned_ho[key3].step}<div>{covidString}</div><div style={{marginTop: "10px"}}><font style={{color: 'blue'}}>{assigned_ho[key3].OneLiner ? assigned_ho[key3].OneLiner : ""}</font></div><div style={{marginTop: "10px"}}>move to <select id={"move_" + assigned_ho[key3].MRN}>{team2}</select> <button style={{marginLeft: '12px'}} onClick={this.runMove} value={assigned_ho[key3].MRN}>submit</button></div><br></br></div>)
                }

            }

           content.push(<div style={{marginBottom: "50px"}}>&nbsp;</div>)
           var disableConfirm = true
           if (this.state.result.HOTeams.length == 0) {
            disableConfirm = false
           }


           content.push(<button disabled={disableConfirm} style={{height: "30px", width: "100px", fontSize: "16px"}} onClick={this.runConfirm}>Confirm</button>)
           content.push(<div style={{marginBottom: "50px"}}>&nbsp;</div>)
        }



        if (this.state.screen == 2) {
            header = ""
            var singleSpace = "10px"
            var paragraphSpace = "50px"
            var doubleSpace = "20px"
            content.push(<div style={{marginTop: "50px"}}>Good morning Everyone</div>)
            content.push(<div style={{marginTop: singleSpace, marginBottom: paragraphSpace}}>{this.state.result.signout}</div>)
            for (var index in this.state.result.block) {
                var block = this.state.result.block[index]
                content.push(<div style={{marginTop: singleSpace}}>{block.type_name}#: {block.block}</div>)
            }
            content.push(<div style={{marginTop: paragraphSpace}}>Macaw please page Hawk (MOD) to get any signout when you arrive.</div>)
            content.push(<div style={{marginTop: paragraphSpace}}>As a reminder, there is no longer a floating cap. Total call day cap: maximum 6 new patients.</div>)
            content.push(<div style={{marginTop: paragraphSpace}}>***Please update first call, treatment team, and attending (and remove night team contact info) on all holdovers before 9am!***</div>)

            content.push(<hr></hr>)

            for (var index in this.state.result.contact) {
                var contact = this.state.result.contact[index]
                content.push(<div style={{color: "brown", marginTop: doubleSpace}}>{contact.team}</div>)
                var infoLine = ""
                infoLine = contact.name
                if (contact.pager.length > 0) {
                    infoLine += " pager/cell:" + contact.pager
                }
                content.push(<div style={{marginTop:singleSpace}}>{infoLine}</div>)
            }


            content.push(<div style={{marginTop: paragraphSpace}}><b>Note: In-person signout for all holdover patients has returned for wards teams. Please meet in your designated team room for all holdovers.</b></div>)

            content.push(<div style={{marginTop: doubleSpace}}>Team Rooms:</div>)

            for (var index in this.state.result.rooms) {
                var room = this.state.result.rooms[index]
                content.push(<div style={{marginTop: doubleSpace}}>{room.name}: {room.room}</div>)
            }


            content.push(<hr></hr>)





            for (var index in this.state.result.team) {
                var team = this.state.result.team[index]
                var amion = ""
                if (team.amion.length > 0) {
                    amion = team.amion[0].name 
                    if (team.amion[0].pager.length > 0) {
                        amion +=  ", " + team.amion[0].pager
                    }
                } 
                var duty = team.duty 
                if (duty.length > 0) {
                    duty = ", " + duty
                }


                content.push(<div style={{marginTop: paragraphSpace}}><u>{team.name} - {amion} ({team.census} pts{duty})</u></div>)


                var groupAssignTeam = Array.from(new Set(team.assigned_ho.map(groups => groups.team.replace("Medicine","").replace("Night","").replace("Attending","").replace("(","").replace(")","").replace("Resident","").replace("1","").replace("2","").replace("4","").replace("Swing","").replace("Shift","").trim()))).map(group => {return {team: group}});

                var hoGroup = ""
                for (var key in groupAssignTeam) {
                    hoGroup += groupAssignTeam[key].team + ", "
                }
                if (hoGroup.length > 0 && team.name.includes("ROUNDING") && team.name.includes("GOLDMAN")) {
                    hoGroup = hoGroup.substring(0, hoGroup.length - 2)
                    hoGroup = "Page " + hoGroup + " before 08:30 AM for sign out"
                    content.push(<div style={{fontSize: "14px", marginTop: "35px", marginLeft: "20px", marginBottom: "10px"}}>{hoGroup}</div>)

                }

                var teamSignoutTime = []
                var findSignoutTime = this.state.result.signoutTime


                for (var index2 in team.assigned_ho) {

                    if (team.name.includes("ROUNDING") && !team.name.includes("GOLDMAN") && !team.name.toLowerCase().includes("cardinal")) {


                        var duration = 15

                        var stopLoop = false
                        var countStop = 30;
                        var counter = 0;


                        while (!stopLoop && counter < countStop) {
                            var teamTime = this.findTeamTimeFunc(findSignoutTime, teamSignoutTime.filter(Record => (Record.team === team.assigned_ho[index2].team)), duration)

                            var signoutTeamTime = this.findTeamTimeFunc(findSignoutTime, globalSignoutTeamTime.filter(Record => (Record.team === team.assigned_ho[index2].team)), duration)

                            if (teamTime != signoutTeamTime) { 
                              if (findSignoutTime === teamTime)
                                findSignoutTime = signoutTeamTime
                              else
                                findSignoutTime = teamTime
                            }
                            else {
                                console.log(findSignoutTime)
                              var d = new Date('1970-01-01T' + this.toggle24hr(findSignoutTime) + ":00")
                              d.setMinutes(d.getMinutes() + duration)
                              teamSignoutTime.push({team: team.assigned_ho[index2].team, startTime: findSignoutTime, endTime: d.toLocaleString([], {hour: '2-digit', minute: '2-digit'})})
                              globalSignoutTeamTime.push({forTeam: team.name, team: team.assigned_ho[index2].team, startTime: findSignoutTime, endTime: d.toLocaleString([], {hour: '2-digit', minute: '2-digit'})})
                              stopLoop = true


                              var teamString = team.assigned_ho[index2].team
                              var teamString = teamString.substring(teamString.indexOf("(")+1,teamString.indexOf(")"))


                              content.push(<div style={{fontSize: "14px", marginTop: "35px", marginLeft: "20px", marginBottom: "10px"}}>Meet {teamString.replace("Medicine","").replace("Night","").replace("Attending","").replace("(","").replace(")","").replace("Resident","").replace("1","").replace("2","").replace("4","").replace("Swing","").replace("Shift","").trim()}  at {findSignoutTime} for sign out in your team room <br></br></div>)


                              findSignoutTime = d.toLocaleString([], {hour: '2-digit', minute: '2-digit'})
                            }
                            counter += 1
                        }



                    }
                    var ho = team.assigned_ho[index2]

                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (ho.COVID.length > 0) {
                        covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {ho.COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + ho.team
                    if (ho.team === "Medicine X Robin") {
                        teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }

                    var remainLocation = ""
                    try {
                        if (ho.Location.length > 0) {
                            remainLocation = " (" + ho.Location + ")"
                        } 
                    } catch (e) {}
                    content.push(<div style={{fontSize: "14px", marginTop: "35px", marginLeft: "20px", marginBottom: "10px"}}><font style={{color: "#8B4513"}}><b>MRN: {ho.MRN} - {ho.Name} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font><div>{covidString}</div><div style={{marginTop: "10px"}}><font style={{color: 'blue'}}>{ho.OneLiner ? ho.OneLiner : ""}</font></div></div>)

                }



            }


            content.push(<div style={{marginTop: paragraphSpace}}>Total # of holdovers = {this.state.result.totalHO}</div>)

            content.push(<div style={{marginTop: paragraphSpace}}>Total # of swing admits = ***</div>)
            content.push(<div style={{marginTop: singleSpace}}>Koala:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Toucan:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Sparrow:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Swing retainer (Robin):</div>)


            content.push(<div style={{marginTop: paragraphSpace}}>Total # of night admits</div>)
            content.push(<div style={{marginTop: singleSpace}}>Badger:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Wolf:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Hawk:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Owl:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Quail:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Eagle:</div>)


            content.push(<div style={{marginTop: paragraphSpace}}>Total # of re-triaged patients</div>)
            content.push(<div style={{marginTop: singleSpace}}>Mt Zion:</div>)
            content.push(<div style={{marginTop: singleSpace}}>St. Mary's:</div>)

            content.push(<div style={{marginTop: paragraphSpace}}>Total # admits by jeopardy/other (please specify) = ***</div>)


            //content.push(<div style={{marginTop: doubleSpace}}><img src={footer}/></div>)
            content.push(<div style={{marginTop: doubleSpace}}><img src="https://applet.ucsf.edu/media/footer.png" width="800px"></img></div>)



            content.push(<div style={{marginBottom: "50px"}}>&nbsp;</div>)
        }



        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberRaptorV2
